        continue
    if norm_id(oid) in order_ids:
        cd = r.get('createddate')
        try:
            dt = datetime.strptime(cd[:19], '%Y-%m-%dT%H:%M:%S')
        except Exception:
            # try alternative formats
            try:
                dt = datetime.fromisoformat(cd)
            except Exception:
                continue
        rows.append({'created': dt, 'orderitemid': norm_id(oid)})

if not rows:
